using NUnit.Framework;
using OpenAI.Responses;
using System;
using System.ClientModel.Primitives;

namespace OpenAI.Tests.Responses;

/// <summary>
/// Tests for ResponsesClientOptions to validate it works correctly.
/// This is a temporary test file that will be deleted after validation.
/// </summary>
[Category("Responses")]
public class ResponsesClientOptionsTests
{
    [Test]
    public void ResponsesClientOptions_DefaultConstructor_CreatesInstance()
    {
        var options = new ResponsesClientOptions();
        Assert.That(options, Is.Not.Null);
        Assert.That(options.Endpoint, Is.Null);
        Assert.That(options.OrganizationId, Is.Null);
        Assert.That(options.ProjectId, Is.Null);
        Assert.That(options.UserAgentApplicationId, Is.Null);
    }

    [Test]
    public void ResponsesClientOptions_Properties_SetAndGet()
    {
        var options = new ResponsesClientOptions
        {
            Endpoint = new Uri("https://example.com/v1/"),
            OrganizationId = "org-123",
            ProjectId = "proj-456",
            UserAgentApplicationId = "my-app",
        };

        Assert.That(options.Endpoint, Is.EqualTo(new Uri("https://example.com/v1/")));
        Assert.That(options.OrganizationId, Is.EqualTo("org-123"));
        Assert.That(options.ProjectId, Is.EqualTo("proj-456"));
        Assert.That(options.UserAgentApplicationId, Is.EqualTo("my-app"));
    }

    [Test]
    public void ResponsesClientOptions_FromClientOptions_Null_ReturnsDefaults()
    {
        var options = ResponsesClientOptions.FromClientOptions(null);
        Assert.That(options, Is.Not.Null);
        Assert.That(options.Endpoint, Is.Null);
        Assert.That(options.OrganizationId, Is.Null);
        Assert.That(options.ProjectId, Is.Null);
        Assert.That(options.UserAgentApplicationId, Is.Null);
    }

    [Test]
    public void ResponsesClientOptions_FromClientOptions_CopiesAllProperties()
    {
        var clientOptions = new OpenAIClientOptions
        {
            Endpoint = new Uri("https://api.openai.com/v1"),
            OrganizationId = "org-test",
            ProjectId = "proj-test",
            UserAgentApplicationId = "app-test",
        };

        var responsesOptions = ResponsesClientOptions.FromClientOptions(clientOptions);

        Assert.That(responsesOptions.Endpoint, Is.EqualTo(clientOptions.Endpoint));
        Assert.That(responsesOptions.OrganizationId, Is.EqualTo(clientOptions.OrganizationId));
        Assert.That(responsesOptions.ProjectId, Is.EqualTo(clientOptions.ProjectId));
        Assert.That(responsesOptions.UserAgentApplicationId, Is.EqualTo(clientOptions.UserAgentApplicationId));
    }

    [Test]
    public void ResponsesClientOptions_IsClientPipelineOptions()
    {
        var options = new ResponsesClientOptions();
        Assert.That(options, Is.InstanceOf<ClientPipelineOptions>());
    }

    [Test]
    public void ResponsesClient_Constructor_WithApiKey_UsesResponsesClientOptions()
    {
        var client = new ResponsesClient("test-api-key");
        Assert.That(client, Is.Not.Null);
        Assert.That(client.Endpoint, Is.Not.Null);
    }

    [Test]
    public void ResponsesClient_Constructor_WithCredential_UsesResponsesClientOptions()
    {
        var credential = new ApiKeyCredential("test-api-key");
        var client = new ResponsesClient(credential);
        Assert.That(client, Is.Not.Null);
        Assert.That(client.Endpoint, Is.Not.Null);
    }

    [Test]
    public void ResponsesClient_Constructor_WithCredentialAndOptions_UsesResponsesClientOptions()
    {
        var credential = new ApiKeyCredential("test-api-key");
        var options = new ResponsesClientOptions
        {
            Endpoint = new Uri("https://example.com/v1/"),
            OrganizationId = "org-123",
        };

        var client = new ResponsesClient(credential, options);
        Assert.That(client, Is.Not.Null);
        Assert.That(client.Endpoint, Is.EqualTo(new Uri("https://example.com/v1/")));
    }

    [Test]
    public void ResponsesClient_Constructor_WithAuthPolicy_UsesResponsesClientOptions()
    {
        var credential = new ApiKeyCredential("test-api-key");
        var authPolicy = ApiKeyAuthenticationPolicy.CreateHeaderApiKeyPolicy(credential, "Authorization", "Bearer");

        var client = new ResponsesClient(authPolicy);
        Assert.That(client, Is.Not.Null);
        Assert.That(client.Endpoint, Is.Not.Null);
    }

    [Test]
    public void ResponsesClient_Constructor_WithAuthPolicyAndOptions_UsesResponsesClientOptions()
    {
        var credential = new ApiKeyCredential("test-api-key");
        var authPolicy = ApiKeyAuthenticationPolicy.CreateHeaderApiKeyPolicy(credential, "Authorization", "Bearer");
        var options = new ResponsesClientOptions
        {
            Endpoint = new Uri("https://example.com/v1/"),
        };

        var client = new ResponsesClient(authPolicy, options);
        Assert.That(client, Is.Not.Null);
        Assert.That(client.Endpoint, Is.EqualTo(new Uri("https://example.com/v1/")));
    }

    [Test]
    public void ResponsesClientOptions_FromClientOptions_StaticMethod_Works()
    {
        // The FromClientOptions is internal, so we can only test it indirectly.
        // We test through the OpenAIClient pipeline flow below.
        Assert.Pass("FromClientOptions is tested indirectly through integration tests");
    }
}

